const articles = $input.first().json.articles || [];

const headlines = articles
  .slice(0, 5)
  .map((a, i) => `**${i + 1}.** ${a.title}`)
  .join("\n");

return [{
  json: {
    headlines
  }
}];

const weather = $node["Weather"].json;
const news = $node["News"].json;
const quote = $node["Quote"].json;

// Format weather
const temp = Math.round(weather.main.temp);
const feelsLike = Math.round(weather.main.feels_like);
const humidity = weather.main.humidity;
const wind = Math.round(weather.wind.speed);

const description = weather.weather[0].description
  .replace(/\b\w/g, c => c.toUpperCase());

// Shorten headlines
const headlines = news.articles
  .slice(0, 3)
  .map(article => {
    let title = article.title.split(" - ")[0]; // Remove source
    if (title.length > 85) title = title.slice(0, 82) + "...";
    return `• ${title}`;
  })
  .join("\n");

// Today's date
const today = new Date().toLocaleDateString("en-US", {
  weekday: "long",
  month: "long",
  day: "numeric",
});

// Clothing recommendation
let advice = "";

if (temp >= 90) {
  advice = "🥵 It's going to be very hot today. Stay hydrated and wear light clothing.";
} else if (temp >= 75) {
  advice = "👕 Warm weather today. Short sleeves should be comfortable.";
} else if (temp >= 60) {
  advice = "🧥 Mild temperatures. A light jacket may be useful this morning.";
} else {
  advice = "🧣 It's quite chilly today. Dress warmly before heading out.";
}

// Final message
const message = `# 🌅 Good Morning!


📅 **${today}**

📍**${$('Location').first().json.city}, ${$('Location').first().json.country_name}** 

## ☀️ Weather

**${temp}°F** • ${description}

🌡️ Feels like: **${feelsLike}°F**
💧 Humidity: **${humidity}%**
🌬️ Wind: **${wind} mph**

${advice}

## 📰 Today's Headlines

${headlines}

## 💪 Quote of the Day

> *"${quote.q}"*

— **${quote.a}**

Have an amazing day! 🚀

─────────────────────────────`;

return [
  {
    json: {
      message
    }
  }
];

const now = new Date();

// Detects your laptop's current travel timezone automatically
const localTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone;

// Format helpers
const formatTime = (options) => {
  return new Intl.DateTimeFormat('en-US', {
    ...options,
    timeZone: localTimezone
  }).format(now);
};

const parts = new Intl.DateTimeFormat('en-US', {
  timeZone: localTimezone,
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit',
  hour12: false
}).formatToParts(now);

const getPart = (type) => parts.find(p => p.type === type).value;

const getOrdinalSuffix = (day) => {
  const d = parseInt(day);
  if (d > 3 && d < 21) return 'th';
  switch (d % 10) {
    case 1:  return "st";
    case 2:  return "nd";
    case 3:  return "rd";
    default: return "th";
  }
};

const dayOfMonth = getPart('day');
const monthName = formatTime({ month: 'long' });
const ordinalDate = `${monthName} ${parseInt(dayOfMonth)}${getOrdinalSuffix(dayOfMonth)} ${getPart('year')}`;

return [{
  "timestamp": now.toISOString(),
  "Readable date": `${ordinalDate}, ${formatTime({ hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true }).toLowerCase()}`,
  "Readable time": formatTime({ hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true }).toLowerCase(),
  "Day of week": formatTime({ weekday: 'long' }),
  "Year": getPart('year'),
  "Month": monthName,
  "Day of month": dayOfMonth,
  "Hour": getPart('hour'),
  "Minute": getPart('minute'),
  "Second": getPart('second'),
  "Timezone": `${localTimezone} (UTC${formatTime({ timeZoneName: 'shortOffset' }).replace('GMT', '')})`
}];
